import{_ as a,o as n,c as e,a2 as o}from"./chunks/framework.B72_uj9U.js";const h=JSON.parse('{"title":"Sandboxing","description":"","frontmatter":{"title":"Sandboxing"},"headers":[],"relativePath":"research/concepts/tool-systems/sandboxing.md","filePath":"research/concepts/tool-systems/sandboxing.md"}'),t={name:"research/concepts/tool-systems/sandboxing.md"};function l(p,s,r,c,i,d){return n(),e("div",null,[...s[0]||(s[0]=[o(`<h1 id="sandboxing" tabindex="-1">Sandboxing <a class="header-anchor" href="#sandboxing" aria-label="Permalink to &quot;Sandboxing&quot;">​</a></h1><p>How coding agents isolate tool execution to prevent dangerous side effects — from Linux kernel primitives to cloud sandbox services.</p><hr><h2 id="_1-why-sandbox" tabindex="-1">1. Why Sandbox? <a class="header-anchor" href="#_1-why-sandbox" aria-label="Permalink to &quot;1. Why Sandbox?&quot;">​</a></h2><p>Code execution is inherently dangerous. Every <code>subprocess.run()</code>, every <code>exec()</code>, every shell invocation is a doorway to the full power of the operating system. For traditional software, this is manageable — developers write the code, review it, test it. But coding agents introduce a fundamentally different threat model: <strong>the code being executed is generated by an LLM</strong>, and LLMs can be wrong, confused, or manipulated.</p><h3 id="the-risks-are-real" tabindex="-1">The Risks Are Real <a class="header-anchor" href="#the-risks-are-real" aria-label="Permalink to &quot;The Risks Are Real&quot;">​</a></h3><p><strong>File system destruction.</strong> An agent asked to &quot;clean up the project&quot; might <code>rm -rf /</code> if the model hallucinates. More subtly, it might delete <code>.git/</code> or overwrite configuration files, causing damage that is hard to detect and harder to reverse.</p><p><strong>Data exfiltration.</strong> A prompt injection hidden in a README could instruct the agent to <code>curl</code> environment variables (containing API keys, tokens) to an attacker&#39;s server. This is not hypothetical — researchers have demonstrated this attack against multiple agent frameworks.</p><p><strong>Cryptocurrency mining.</strong> An agent with unrestricted compute access could be tricked into downloading and running a miner. The user pays for the compute; the attacker profits.</p><p><strong>Supply chain attacks.</strong> An agent running <code>pip install</code> or <code>npm install</code> could pull in a malicious package that executes arbitrary code during installation. The agent itself becomes the attack vector into the developer&#39;s environment.</p><p><strong>Lateral movement.</strong> On a developer&#39;s machine, an agent has access to SSH keys, cloud credentials, browser cookies, and other secrets. A compromised agent could pivot to production systems.</p><h3 id="the-fundamental-tension" tabindex="-1">The Fundamental Tension <a class="header-anchor" href="#the-fundamental-tension" aria-label="Permalink to &quot;The Fundamental Tension&quot;">​</a></h3><p>Agents NEED to modify files and run commands — that is their entire purpose. A coding agent that cannot write code or run tests is useless. But unrestricted access to the host system is dangerous. Sandboxing is the art of finding the narrow path between &quot;useful enough to do real work&quot; and &quot;restricted enough to prevent catastrophe.&quot;</p><p>The challenge is that the boundary between &quot;intended side effect&quot; and &quot;dangerous side effect&quot; is context-dependent. Writing to <code>src/main.py</code> is expected; writing to <code>/etc/passwd</code> is not. Running <code>pytest</code> is fine; running <code>curl</code> to an unknown server is suspicious. Sandboxing must encode these distinctions.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>  +---------------------------------------------+</span></span>
<span class="line"><span>  |  LLM generates code/commands                |</span></span>
<span class="line"><span>  |  (may be wrong, malicious, or manipulated)  |</span></span>
<span class="line"><span>  +---------------------------------------------+</span></span>
<span class="line"><span>  |           SANDBOX BOUNDARY                  |</span></span>
<span class="line"><span>  |  +---------------------------------------+  |</span></span>
<span class="line"><span>  |  |  Controlled execution environment     |  |</span></span>
<span class="line"><span>  |  |  * Limited filesystem access          |  |</span></span>
<span class="line"><span>  |  |  * Restricted network                 |  |</span></span>
<span class="line"><span>  |  |  * Filtered syscalls                  |  |</span></span>
<span class="line"><span>  |  |  * Resource limits                    |  |</span></span>
<span class="line"><span>  |  +---------------------------------------+  |</span></span>
<span class="line"><span>  +---------------------------------------------+</span></span>
<span class="line"><span>  |  Host system (protected)                    |</span></span>
<span class="line"><span>  +---------------------------------------------+</span></span></code></pre></div><hr><h2 id="_2-codex-s-3-layer-approach-—-the-most-sophisticated" tabindex="-1">2. Codex&#39;s 3-Layer Approach — The Most Sophisticated <a class="header-anchor" href="#_2-codex-s-3-layer-approach-—-the-most-sophisticated" aria-label="Permalink to &quot;2. Codex&#39;s 3-Layer Approach — The Most Sophisticated&quot;">​</a></h2><p>OpenAI&#39;s Codex CLI implements the most layered sandbox architecture among open-source coding agents, combining three independent Linux security mechanisms that compose defensively — if one layer fails, the others still protect the system.</p><h3 id="layer-1-bubblewrap-user-namespace-isolation" tabindex="-1">Layer 1: bubblewrap (User Namespace Isolation) <a class="header-anchor" href="#layer-1-bubblewrap-user-namespace-isolation" aria-label="Permalink to &quot;Layer 1: bubblewrap (User Namespace Isolation)&quot;">​</a></h3><p><a href="https://github.com/containers/bubblewrap" target="_blank" rel="noreferrer">bubblewrap</a> (<code>bwrap</code>) is a lightweight unprivileged sandboxing tool that uses Linux namespaces to create isolated environments without requiring root access.</p><p>Codex uses bwrap to create five types of isolation:</p><p><strong>Mount namespace.</strong> The entire filesystem is bind-mounted read-only by default. Only explicitly specified directories (the project workspace, <code>/tmp</code>) are mounted writable. The agent can read system libraries and tools but cannot modify them.</p><p><strong>PID namespace.</strong> Processes inside the sandbox cannot see or signal processes outside. The sandboxed process tree is completely isolated — <code>kill -9 1</code> inside the sandbox kills only the sandbox&#39;s init process, not the host&#39;s.</p><p><strong>User namespace.</strong> UID/GID mapping creates an unprivileged user inside the sandbox even if the outer process has elevated privileges. This prevents privilege escalation.</p><p><strong>Network namespace.</strong> All networking is blocked by default. The sandbox has no network interfaces except loopback. Crucially, only <code>AF_UNIX</code> (Unix domain) sockets are permitted — this allows the agent to communicate with its parent process via a pre-established socket without allowing arbitrary network access.</p><p><strong>IPC namespace.</strong> Shared memory segments and semaphores are isolated, preventing inter-process communication with host processes.</p><p>Example bwrap invocation (simplified from Codex source):</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#89B4FA;font-style:italic;">bwrap</span><span style="color:#F5C2E7;"> \\</span></span>
<span class="line"><span style="color:#A6E3A1;">  --ro-bind</span><span style="color:#A6E3A1;"> /</span><span style="color:#A6E3A1;"> /</span><span style="color:#F5C2E7;">                          \\</span></span>
<span class="line"><span style="color:#A6E3A1;">  --bind</span><span style="color:#A6E3A1;"> /home/user/project</span><span style="color:#A6E3A1;"> /workspace</span><span style="color:#F5C2E7;">   \\</span></span>
<span class="line"><span style="color:#A6E3A1;">  --bind</span><span style="color:#A6E3A1;"> /tmp</span><span style="color:#A6E3A1;"> /tmp</span><span style="color:#F5C2E7;">                       \\</span></span>
<span class="line"><span style="color:#A6E3A1;">  --tmpfs</span><span style="color:#A6E3A1;"> /run</span><span style="color:#F5C2E7;">                           \\</span></span>
<span class="line"><span style="color:#A6E3A1;">  --dev</span><span style="color:#A6E3A1;"> /dev</span><span style="color:#F5C2E7;">                             \\</span></span>
<span class="line"><span style="color:#A6E3A1;">  --proc</span><span style="color:#A6E3A1;"> /proc</span><span style="color:#F5C2E7;">                           \\</span></span>
<span class="line"><span style="color:#A6E3A1;">  --unshare-pid</span><span style="color:#F5C2E7;">                          \\</span></span>
<span class="line"><span style="color:#A6E3A1;">  --unshare-net</span><span style="color:#F5C2E7;">                          \\</span></span>
<span class="line"><span style="color:#A6E3A1;">  --unshare-ipc</span><span style="color:#F5C2E7;">                          \\</span></span>
<span class="line"><span style="color:#A6E3A1;">  --unshare-user</span><span style="color:#F5C2E7;">                         \\</span></span>
<span class="line"><span style="color:#A6E3A1;">  --uid</span><span style="color:#FAB387;"> 1000</span><span style="color:#A6E3A1;"> --gid</span><span style="color:#FAB387;"> 1000</span><span style="color:#F5C2E7;">                  \\</span></span>
<span class="line"><span style="color:#A6E3A1;">  --die-with-parent</span><span style="color:#F5C2E7;">                      \\</span></span>
<span class="line"><span style="color:#A6E3A1;">  --new-session</span><span style="color:#F5C2E7;">                          \\</span></span>
<span class="line"><span style="color:#A6E3A1;">  --</span><span style="color:#A6E3A1;"> /bin/bash</span><span style="color:#A6E3A1;"> -c</span><span style="color:#A6E3A1;"> &quot;</span><span style="color:#CDD6F4;">$COMMAND</span><span style="color:#A6E3A1;">&quot;</span></span></code></pre></div><p>The flags break down as:</p><ul><li><code>--ro-bind / /</code> — Mount the entire root filesystem read-only</li><li><code>--bind ... /workspace</code> — Mount the project directory writable</li><li><code>--unshare-pid</code> — Create new PID namespace</li><li><code>--unshare-net</code> — Create new network namespace (no connectivity)</li><li><code>--unshare-user</code> — Create new user namespace</li><li><code>--die-with-parent</code> — Kill sandbox if parent process dies (prevents orphans)</li></ul><h3 id="layer-2-seccomp-syscall-filtering" tabindex="-1">Layer 2: seccomp (Syscall Filtering) <a class="header-anchor" href="#layer-2-seccomp-syscall-filtering" aria-label="Permalink to &quot;Layer 2: seccomp (Syscall Filtering)&quot;">​</a></h3><p>Even within an isolated namespace, the kernel surface is large. seccomp-bpf (Secure Computing mode with Berkeley Packet Filters) allows a process to install a filter that restricts which system calls it can make.</p><p>Codex installs a seccomp filter that:</p><p><strong>Blocks dangerous syscalls:</strong></p><ul><li><code>ptrace</code> — prevents debugging/tracing other processes</li><li><code>io_uring_setup</code>, <code>io_uring_enter</code>, <code>io_uring_register</code> — blocks io_uring which has been a source of kernel exploits</li><li><code>socket(AF_INET, ...)</code>, <code>socket(AF_INET6, ...)</code> — blocks TCP/UDP network sockets</li><li><code>mount</code>, <code>umount2</code> — prevents filesystem manipulation</li><li><code>reboot</code>, <code>kexec_load</code> — prevents system disruption</li><li><code>init_module</code>, <code>finit_module</code> — prevents kernel module loading</li></ul><p><strong>Allows only AF_UNIX sockets</strong> for IPC with the parent process:</p><div class="language-c"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;">// Pseudocode for seccomp BPF filter</span></span>
<span class="line"><span style="color:#CBA6F7;">struct</span><span style="color:#CDD6F4;"> sock_filter filter</span><span style="color:#CBA6F7;">[]</span><span style="color:#94E2D5;"> =</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // Load syscall number</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    BPF_STMT</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">BPF_LD </span><span style="color:#94E2D5;">|</span><span style="color:#CDD6F4;"> BPF_W </span><span style="color:#94E2D5;">|</span><span style="color:#CDD6F4;"> BPF_ABS</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">             offsetof</span><span style="color:#9399B2;">(</span><span style="color:#CBA6F7;">struct</span><span style="color:#CDD6F4;"> seccomp_data</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> nr</span><span style="color:#9399B2;">)),</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // Block ptrace</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    BPF_JUMP</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">BPF_JMP </span><span style="color:#94E2D5;">|</span><span style="color:#CDD6F4;"> BPF_JEQ </span><span style="color:#94E2D5;">|</span><span style="color:#CDD6F4;"> BPF_K</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> __NR_ptrace</span><span style="color:#9399B2;">,</span><span style="color:#FAB387;"> 0</span><span style="color:#9399B2;">,</span><span style="color:#FAB387;"> 1</span><span style="color:#9399B2;">),</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    BPF_STMT</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">BPF_RET </span><span style="color:#94E2D5;">|</span><span style="color:#CDD6F4;"> BPF_K</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> SECCOMP_RET_ERRNO </span><span style="color:#94E2D5;">|</span><span style="color:#CDD6F4;"> EPERM</span><span style="color:#9399B2;">),</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // For socket(), inspect the domain argument</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    BPF_JUMP</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">BPF_JMP </span><span style="color:#94E2D5;">|</span><span style="color:#CDD6F4;"> BPF_JEQ </span><span style="color:#94E2D5;">|</span><span style="color:#CDD6F4;"> BPF_K</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> __NR_socket</span><span style="color:#9399B2;">,</span><span style="color:#FAB387;"> 0</span><span style="color:#9399B2;">,</span><span style="color:#FAB387;"> 4</span><span style="color:#9399B2;">),</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    BPF_STMT</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">BPF_LD </span><span style="color:#94E2D5;">|</span><span style="color:#CDD6F4;"> BPF_W </span><span style="color:#94E2D5;">|</span><span style="color:#CDD6F4;"> BPF_ABS</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">             offsetof</span><span style="color:#9399B2;">(</span><span style="color:#CBA6F7;">struct</span><span style="color:#CDD6F4;"> seccomp_data</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> args</span><span style="color:#9399B2;">[</span><span style="color:#FAB387;">0</span><span style="color:#9399B2;">])),</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // Allow AF_UNIX (domain = 1)</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    BPF_JUMP</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">BPF_JMP </span><span style="color:#94E2D5;">|</span><span style="color:#CDD6F4;"> BPF_JEQ </span><span style="color:#94E2D5;">|</span><span style="color:#CDD6F4;"> BPF_K</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> AF_UNIX</span><span style="color:#9399B2;">,</span><span style="color:#FAB387;"> 0</span><span style="color:#9399B2;">,</span><span style="color:#FAB387;"> 1</span><span style="color:#9399B2;">),</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    BPF_STMT</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">BPF_RET </span><span style="color:#94E2D5;">|</span><span style="color:#CDD6F4;"> BPF_K</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> SECCOMP_RET_ALLOW</span><span style="color:#9399B2;">),</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // Block all other socket domains</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    BPF_STMT</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">BPF_RET </span><span style="color:#94E2D5;">|</span><span style="color:#CDD6F4;"> BPF_K</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> SECCOMP_RET_ERRNO </span><span style="color:#94E2D5;">|</span><span style="color:#CDD6F4;"> EPERM</span><span style="color:#9399B2;">),</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // Default: allow</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    BPF_STMT</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">BPF_RET </span><span style="color:#94E2D5;">|</span><span style="color:#CDD6F4;"> BPF_K</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> SECCOMP_RET_ALLOW</span><span style="color:#9399B2;">),</span></span>
<span class="line"><span style="color:#9399B2;">};</span></span></code></pre></div><p>The key insight is filtering at the <em>argument</em> level, not just the syscall level. The <code>socket()</code> syscall itself is allowed, but only with <code>AF_UNIX</code> as the domain argument. This enables inter-process communication while blocking network access.</p><h3 id="layer-3-landlock-filesystem-access-control" tabindex="-1">Layer 3: Landlock (Filesystem Access Control) <a class="header-anchor" href="#layer-3-landlock-filesystem-access-control" aria-label="Permalink to &quot;Layer 3: Landlock (Filesystem Access Control)&quot;">​</a></h3><p><a href="https://landlock.io/" target="_blank" rel="noreferrer">Landlock</a> is a Linux Security Module (available since kernel 5.13) that enables unprivileged processes to restrict their own filesystem access. Unlike traditional LSMs (SELinux, AppArmor) which require admin configuration, Landlock rules are self-imposed by the process.</p><p>Codex uses Landlock as a defense-in-depth layer and as a fallback when bubblewrap is not available (e.g., in containers where user namespaces are disabled):</p><div class="language-c"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;">// Pseudocode for Landlock ruleset</span></span>
<span class="line"><span style="color:#CBA6F7;">struct</span><span style="color:#CDD6F4;"> landlock_ruleset_attr attr </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CDD6F4;">    .handled_access_fs </span><span style="color:#94E2D5;">=</span></span>
<span class="line"><span style="color:#CDD6F4;">        LANDLOCK_ACCESS_FS_READ_FILE </span><span style="color:#94E2D5;">|</span></span>
<span class="line"><span style="color:#CDD6F4;">        LANDLOCK_ACCESS_FS_WRITE_FILE </span><span style="color:#94E2D5;">|</span></span>
<span class="line"><span style="color:#CDD6F4;">        LANDLOCK_ACCESS_FS_EXECUTE </span><span style="color:#94E2D5;">|</span></span>
<span class="line"><span style="color:#CDD6F4;">        LANDLOCK_ACCESS_FS_MAKE_DIR </span><span style="color:#94E2D5;">|</span></span>
<span class="line"><span style="color:#CDD6F4;">        LANDLOCK_ACCESS_FS_REMOVE_FILE</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">};</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">int</span><span style="color:#CDD6F4;"> ruleset_fd </span><span style="color:#94E2D5;">=</span><span style="color:#89B4FA;font-style:italic;"> landlock_create_ruleset</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">&amp;</span><span style="color:#EBA0AC;font-style:italic;">attr</span><span style="color:#9399B2;">,</span><span style="color:#94E2D5;"> sizeof</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">attr</span><span style="color:#9399B2;">),</span><span style="color:#FAB387;"> 0</span><span style="color:#9399B2;">);</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">// Allow read-only access to /usr, /lib, /etc</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">add_path_rule</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">ruleset_fd</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;/usr&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">    LANDLOCK_ACCESS_FS_READ_FILE </span><span style="color:#94E2D5;">|</span><span style="color:#CDD6F4;"> EXECUTE</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">add_path_rule</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">ruleset_fd</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;/lib&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">    LANDLOCK_ACCESS_FS_READ_FILE </span><span style="color:#94E2D5;">|</span><span style="color:#CDD6F4;"> EXECUTE</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">add_path_rule</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">ruleset_fd</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;/etc&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">    LANDLOCK_ACCESS_FS_READ_FILE</span><span style="color:#9399B2;">);</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">// Allow full access to workspace</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">add_path_rule</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">ruleset_fd</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;/workspace&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> ALL_ACCESS</span><span style="color:#9399B2;">);</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">// Enforce! (irreversible for this process)</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">landlock_restrict_self</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">ruleset_fd</span><span style="color:#9399B2;">,</span><span style="color:#FAB387;"> 0</span><span style="color:#9399B2;">);</span></span></code></pre></div><p>The critical property of Landlock is that it is <strong>irreversible</strong> — once a process calls <code>landlock_restrict_self()</code>, it cannot remove or weaken the restrictions. Even if the agent gains code execution, it cannot escape the Landlock sandbox.</p><h3 id="how-the-three-layers-compose" tabindex="-1">How the Three Layers Compose <a class="header-anchor" href="#how-the-three-layers-compose" aria-label="Permalink to &quot;How the Three Layers Compose&quot;">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>  Process Start</span></span>
<span class="line"><span>    |</span></span>
<span class="line"><span>    v</span></span>
<span class="line"><span>  +--------------------------------------+</span></span>
<span class="line"><span>  |  Landlock: restrict filesystem paths |  &lt;-- Self-imposed path restrictions</span></span>
<span class="line"><span>  |  (read-only: /usr, /lib, /etc)       |</span></span>
<span class="line"><span>  |  (read-write: /workspace, /tmp)      |</span></span>
<span class="line"><span>  +--------------------------------------+</span></span>
<span class="line"><span>                 |</span></span>
<span class="line"><span>                 v</span></span>
<span class="line"><span>  +--------------------------------------+</span></span>
<span class="line"><span>  |  bubblewrap: create namespaces       |  &lt;-- OS-level process isolation</span></span>
<span class="line"><span>  |  * Mount namespace (ro root)         |</span></span>
<span class="line"><span>  |  * PID namespace                     |</span></span>
<span class="line"><span>  |  * Network namespace (no net)        |</span></span>
<span class="line"><span>  |  * User namespace (unprivileged)     |</span></span>
<span class="line"><span>  +--------------------------------------+</span></span>
<span class="line"><span>                 |</span></span>
<span class="line"><span>                 v</span></span>
<span class="line"><span>  +--------------------------------------+</span></span>
<span class="line"><span>  |  seccomp: filter syscalls            |  &lt;-- Kernel-level syscall filtering</span></span>
<span class="line"><span>  |  * Block: ptrace, io_uring, mount    |</span></span>
<span class="line"><span>  |  * Allow: AF_UNIX sockets only       |</span></span>
<span class="line"><span>  +--------------------------------------+</span></span>
<span class="line"><span>                 |</span></span>
<span class="line"><span>                 v</span></span>
<span class="line"><span>  +--------------------------------------+</span></span>
<span class="line"><span>  |  Execute command                     |</span></span>
<span class="line"><span>  +--------------------------------------+</span></span></code></pre></div><p>Each layer defends against different failure modes:</p><ul><li>Landlock fails? bubblewrap&#39;s read-only mounts prevent writes.</li><li>bubblewrap fails? seccomp blocks dangerous syscalls.</li><li>seccomp bypassed? Landlock still restricts filesystem access.</li><li>All three must be defeated simultaneously for a complete escape.</li></ul><h3 id="cross-platform-support" tabindex="-1">Cross-Platform Support <a class="header-anchor" href="#cross-platform-support" aria-label="Permalink to &quot;Cross-Platform Support&quot;">​</a></h3><p><strong>macOS: Seatbelt</strong> (<code>sandbox-exec</code>). Codex uses Apple&#39;s <code>sandbox-exec</code> with a custom Scheme-based profile that denies network access and restricts filesystem writes. Seatbelt is less granular than the Linux stack but provides meaningful isolation on macOS:</p><div class="language-scheme"><button title="Copy Code" class="copy"></button><span class="lang">scheme</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">version </span><span style="color:#FAB387;">1</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">deny default</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">allow process-exec</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">allow file-read*</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">allow file-write*</span></span>
<span class="line"><span style="color:#9399B2;">  (</span><span style="color:#CDD6F4;">subpath </span><span style="color:#A6E3A1;">&quot;/Users/user/project&quot;</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#9399B2;">  (</span><span style="color:#CDD6F4;">subpath </span><span style="color:#A6E3A1;">&quot;/tmp&quot;</span><span style="color:#9399B2;">))</span></span>
<span class="line"><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">deny network*</span><span style="color:#9399B2;">)</span></span></code></pre></div><p><strong>Windows:</strong> Restricted tokens, ACLs, and Windows Firewall rules provide isolation, though with less granularity than the Linux namespace approach.</p><h3 id="proxy-routing-for-controlled-network-access" tabindex="-1">Proxy Routing for Controlled Network Access <a class="header-anchor" href="#proxy-routing-for-controlled-network-access" aria-label="Permalink to &quot;Proxy Routing for Controlled Network Access&quot;">​</a></h3><p>When agents need network access (e.g., to install packages), Codex uses a TCP-to-UDS-to-TCP bridge. The agent connects to a Unix domain socket (allowed by seccomp), which is bridged by the host process to actual TCP, applying allowlists:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>  Agent (sandboxed)          Host Process              Internet</span></span>
<span class="line"><span>  +----------+     UDS      +------------+    TCP    +----------+</span></span>
<span class="line"><span>  | curl pkg | ----------&gt;  | Proxy with | -------&gt; | Registry |</span></span>
<span class="line"><span>  |          |   (allowed)  | allowlist  | (filtered)|         |</span></span>
<span class="line"><span>  +----------+              +------------+           +----------+</span></span></code></pre></div><p>Only connections to approved domains (PyPI, npm registry, etc.) are forwarded. All other connection attempts are rejected by the proxy. This gives agents the ability to install dependencies while preventing data exfiltration.</p><hr><h2 id="_3-docker-based-openhands" tabindex="-1">3. Docker-Based: OpenHands <a class="header-anchor" href="#_3-docker-based-openhands" aria-label="Permalink to &quot;3. Docker-Based: OpenHands&quot;">​</a></h2><p><a href="https://github.com/All-Hands-AI/OpenHands" target="_blank" rel="noreferrer">OpenHands</a> (formerly OpenDevin) takes a different approach: every action executes inside a Docker container. This provides strong isolation through the container boundary but at higher startup cost.</p><h3 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>  +------------------------------------------------------------+</span></span>
<span class="line"><span>  |  Host System                                               |</span></span>
<span class="line"><span>  |                                                            |</span></span>
<span class="line"><span>  |  +------------------+      HTTP        +----------------+  |</span></span>
<span class="line"><span>  |  |  AgentController |  &lt;------------&gt;  |  Docker        |  |</span></span>
<span class="line"><span>  |  |                  |                  |  Container     |  |</span></span>
<span class="line"><span>  |  |  * LLM interface |                  |  +----------+  |  |</span></span>
<span class="line"><span>  |  |  * Event stream  |                  |  | Action   |  |  |</span></span>
<span class="line"><span>  |  |  * State machine |                  |  | Execution|  |  |</span></span>
<span class="line"><span>  |  |                  |                  |  | Server   |  |  |</span></span>
<span class="line"><span>  |  +------------------+                  |  +----------+  |  |</span></span>
<span class="line"><span>  |                                        |  +----------+  |  |</span></span>
<span class="line"><span>  |                                        |  | Jupyter  |  |  |</span></span>
<span class="line"><span>  |                                        |  | Kernel   |  |  |</span></span>
<span class="line"><span>  |                                        |  +----------+  |  |</span></span>
<span class="line"><span>  |                                        |  +----------+  |  |</span></span>
<span class="line"><span>  |                                        |  | Browser  |  |  |</span></span>
<span class="line"><span>  |                                        |  |(Playwrght)|  |  |</span></span>
<span class="line"><span>  |                                        |  +----------+  |  |</span></span>
<span class="line"><span>  |                                        |  +----------+  |  |</span></span>
<span class="line"><span>  |                                        |  | Bash     |  |  |</span></span>
<span class="line"><span>  |                                        |  | Shell    |  |  |</span></span>
<span class="line"><span>  |                                        |  +----------+  |  |</span></span>
<span class="line"><span>  |                                        +----------------+  |</span></span>
<span class="line"><span>  +------------------------------------------------------------+</span></span></code></pre></div><h3 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h3><ol><li><p><strong>EventStreamRuntime</strong> creates a Docker container from a pre-built image containing all necessary tools (Python, Node.js, git, etc.).</p></li><li><p><strong>ActionExecutionServer</strong> runs inside the container, listening on a port mapped to the host. It receives <code>Action</code> objects (shell commands, file writes, browser actions) over HTTP and returns <code>Observation</code> results.</p></li><li><p><strong>All tools execute inside the container:</strong></p><ul><li>Shell commands via <code>bash</code></li><li>Code execution via an IPython/Jupyter kernel</li><li>Web browsing via Playwright (headless Chromium inside the container)</li><li>File operations scoped to the container filesystem</li></ul></li><li><p><strong>The project directory is volume-mounted</strong> into the container, giving the agent read-write access to the code being worked on while isolating everything else.</p></li></ol><h3 id="trade-offs" tabindex="-1">Trade-offs <a class="header-anchor" href="#trade-offs" aria-label="Permalink to &quot;Trade-offs&quot;">​</a></h3><p><strong>Advantages:</strong></p><ul><li>Battle-tested isolation (Docker has years of security hardening)</li><li>Full Linux environment inside the container</li><li>Easy to reproduce — containers are deterministic</li><li>Network can be controlled via Docker network policies</li><li>Clean environment for each task (no state leakage)</li></ul><p><strong>Disadvantages:</strong></p><ul><li>Container startup adds 2-10 seconds of latency</li><li>Docker daemon must be running (not always available in CI/restricted envs)</li><li>Volume mounts can be tricky (permission issues, symlinks)</li><li>Heavier resource usage than namespace-only approaches</li><li>Image size can be large (1-5 GB for full development environments)</li></ul><p>OpenHands also supports a <strong>remote sandbox runtime</strong> where containers run on a separate machine, providing even stronger isolation at the cost of network latency.</p><hr><h2 id="_4-gvisor" tabindex="-1">4. gVisor <a class="header-anchor" href="#_4-gvisor" aria-label="Permalink to &quot;4. gVisor&quot;">​</a></h2><p><a href="https://gvisor.dev/" target="_blank" rel="noreferrer">gVisor</a> is Google&#39;s application kernel — a fundamentally different approach to sandboxing that does not fit neatly into the &quot;namespace&quot; or &quot;VM&quot; categories.</p><h3 id="what-gvisor-is-and-is-not" tabindex="-1">What gVisor Is (and Is Not) <a class="header-anchor" href="#what-gvisor-is-and-is-not" aria-label="Permalink to &quot;What gVisor Is (and Is Not)&quot;">​</a></h3><p>gVisor is NOT a syscall filter like seccomp. Seccomp decides whether to allow or block a syscall; gVisor <strong>re-implements</strong> the syscall entirely. When a sandboxed process calls <code>open()</code>, gVisor&#39;s Sentry component handles the call in userspace Go code, never passing it to the host kernel.</p><p>gVisor is NOT a virtual machine. There is no hardware virtualization, no guest kernel running in a VM. It is a userspace process that pretends to be a kernel.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>  Traditional Container          gVisor Container</span></span>
<span class="line"><span>  +--------------+               +--------------+</span></span>
<span class="line"><span>  |  Application |               |  Application |</span></span>
<span class="line"><span>  +------+-------+               +------+-------+</span></span>
<span class="line"><span>         | syscall                       | syscall</span></span>
<span class="line"><span>         v                               v</span></span>
<span class="line"><span>  +--------------+               +--------------+</span></span>
<span class="line"><span>  |  Host Kernel |               |  Sentry      |  &lt;-- Userspace Go process</span></span>
<span class="line"><span>  |  (shared!)   |               |  (gVisor)    |      re-implements syscalls</span></span>
<span class="line"><span>  +--------------+               +------+-------+</span></span>
<span class="line"><span>                                        | limited syscalls</span></span>
<span class="line"><span>                                        v</span></span>
<span class="line"><span>                                 +--------------+</span></span>
<span class="line"><span>                                 |  Host Kernel |  &lt;-- Much smaller surface</span></span>
<span class="line"><span>                                 +--------------+</span></span></code></pre></div><h3 id="key-properties" tabindex="-1">Key Properties <a class="header-anchor" href="#key-properties" aria-label="Permalink to &quot;Key Properties&quot;">​</a></h3><ul><li><strong>OCI-compatible</strong> via the <code>runsc</code> runtime — drop-in replacement for <code>runc</code></li><li><strong>Works with Docker and Kubernetes</strong>: <code>docker run --runtime=runsc</code></li><li><strong>~5-15% CPU overhead</strong> for compute-bound workloads; higher for syscall-heavy loads</li><li><strong>~350 of ~400 Linux syscalls</strong> implemented</li><li><strong>Used in production</strong> by Google Cloud Run, GKE Sandbox</li></ul><h3 id="when-to-use-for-agents" tabindex="-1">When to Use for Agents <a class="header-anchor" href="#when-to-use-for-agents" aria-label="Permalink to &quot;When to Use for Agents&quot;">​</a></h3><p>gVisor is ideal when you need container-like ease of use with VM-like security. For agent sandboxing, it provides stronger isolation than Docker&#39;s default <code>runc</code> runtime because even if the agent finds a container escape exploit, it would escape into gVisor&#39;s userspace kernel, not the real host kernel.</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Run agent container with gVisor</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">docker</span><span style="color:#A6E3A1;"> run</span><span style="color:#A6E3A1;"> --runtime=runsc</span><span style="color:#F5C2E7;"> \\</span></span>
<span class="line"><span style="color:#A6E3A1;">  -v</span><span style="color:#A6E3A1;"> /path/to/project:/workspace</span><span style="color:#F5C2E7;"> \\</span></span>
<span class="line"><span style="color:#A6E3A1;">  --network=none</span><span style="color:#F5C2E7;"> \\</span></span>
<span class="line"><span style="color:#A6E3A1;">  agent-image:latest</span></span></code></pre></div><p>The overhead is acceptable for coding agents because the bottleneck is typically LLM API latency (seconds), not syscall overhead (microseconds).</p><p>gVisor also provides <strong>Gofer</strong>, a separate process that handles filesystem operations. This means even the Sentry (which handles all other syscalls) cannot directly access the host filesystem — true defense in depth.</p><hr><h2 id="_5-e2b" tabindex="-1">5. E2B <a class="header-anchor" href="#_5-e2b" aria-label="Permalink to &quot;5. E2B&quot;">​</a></h2><p><a href="https://e2b.dev/" target="_blank" rel="noreferrer">E2B</a> provides cloud sandboxes purpose-built for AI code execution. Rather than building sandbox infrastructure yourself, E2B offers sandboxes as a service via API.</p><h3 id="how-it-works-1" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works-1" aria-label="Permalink to &quot;How It Works&quot;">​</a></h3><p>Each sandbox is a lightweight microVM (based on Firecracker) that boots in ~150ms. The sandbox has its own filesystem, network stack, and process tree — fully isolated from other sandboxes and the host.</p><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">from</span><span style="color:#CDD6F4;"> e2b </span><span style="color:#CBA6F7;">import</span><span style="color:#CDD6F4;"> Sandbox</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Create a sandbox (boots in ~150ms)</span></span>
<span class="line"><span style="color:#CDD6F4;">sandbox </span><span style="color:#94E2D5;">=</span><span style="color:#89B4FA;"> Sandbox</span><span style="color:#9399B2;">()</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Execute code</span></span>
<span class="line"><span style="color:#CDD6F4;">result </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> sandbox</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">run_code</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;print(&#39;Hello from sandbox!&#39;)&quot;</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#FAB387;font-style:italic;">print</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">result</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">text</span><span style="color:#9399B2;">)</span><span style="color:#6C7086;font-style:italic;">  # &quot;Hello from sandbox!&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Run shell commands</span></span>
<span class="line"><span style="color:#CDD6F4;">proc </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> sandbox</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">commands</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">run</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;ls -la /&quot;</span><span style="color:#9399B2;">)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Upload/download files</span></span>
<span class="line"><span style="color:#CDD6F4;">sandbox</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">files</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">write</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;/home/user/data.csv&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> csv_content</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#CDD6F4;">content </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> sandbox</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">files</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">read</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;/home/user/output.txt&quot;</span><span style="color:#9399B2;">)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Sandbox auto-destroys after timeout (default 5 min)</span></span>
<span class="line"><span style="color:#CDD6F4;">sandbox</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">close</span><span style="color:#9399B2;">()</span></span></code></pre></div><h3 id="templates" tabindex="-1">Templates <a class="header-anchor" href="#templates" aria-label="Permalink to &quot;Templates&quot;">​</a></h3><p>E2B supports custom templates that define the sandbox environment:</p><div class="language-dockerfile"><button title="Copy Code" class="copy"></button><span class="lang">dockerfile</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># e2b.Dockerfile</span></span>
<span class="line"><span style="color:#CBA6F7;">FROM</span><span style="color:#CDD6F4;"> e2b/base:latest</span></span>
<span class="line"><span style="color:#CBA6F7;">RUN</span><span style="color:#CDD6F4;"> pip install numpy pandas matplotlib</span></span>
<span class="line"><span style="color:#CBA6F7;">RUN</span><span style="color:#CDD6F4;"> npm install -g typescript</span></span>
<span class="line"><span style="color:#CBA6F7;">COPY</span><span style="color:#CDD6F4;"> config/ /home/user/.config/</span></span></code></pre></div><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#89B4FA;font-style:italic;">e2b</span><span style="color:#A6E3A1;"> template</span><span style="color:#A6E3A1;"> build</span><span style="color:#A6E3A1;"> -d</span><span style="color:#A6E3A1;"> e2b.Dockerfile</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Returns a template ID to use when creating sandboxes</span></span></code></pre></div><h3 id="key-features" tabindex="-1">Key Features <a class="header-anchor" href="#key-features" aria-label="Permalink to &quot;Key Features&quot;">​</a></h3><ul><li><strong>Python and JavaScript SDKs</strong> for easy integration</li><li><strong>Self-hostable on GCP</strong> for data sovereignty requirements</li><li><strong>Persistent sandboxes</strong> — can pause and resume</li><li><strong>Internet access</strong> — sandboxes can reach the internet (configurable)</li><li><strong>File system snapshots</strong> — save and restore sandbox state</li><li><strong>Streaming output</strong> — real-time stdout/stderr</li></ul><h3 id="integration-with-agent-frameworks" tabindex="-1">Integration with Agent Frameworks <a class="header-anchor" href="#integration-with-agent-frameworks" aria-label="Permalink to &quot;Integration with Agent Frameworks&quot;">​</a></h3><p>E2B integrates with LangChain, CrewAI, and other frameworks as a tool:</p><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">from</span><span style="color:#CDD6F4;"> e2b </span><span style="color:#CBA6F7;">import</span><span style="color:#CDD6F4;"> Sandbox</span></span>
<span class="line"><span style="color:#CBA6F7;">from</span><span style="color:#CDD6F4;"> langchain</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">tools </span><span style="color:#CBA6F7;">import</span><span style="color:#CDD6F4;"> tool</span></span>
<span class="line"></span>
<span class="line"><span style="color:#FAB387;font-style:italic;">@tool</span></span>
<span class="line"><span style="color:#CBA6F7;">def</span><span style="color:#89B4FA;font-style:italic;"> execute_code</span><span style="color:#9399B2;">(</span><span style="color:#EBA0AC;font-style:italic;">code</span><span style="color:#9399B2;">:</span><span style="color:#FAB387;font-style:italic;"> str</span><span style="color:#9399B2;">)</span><span style="color:#9399B2;"> -&gt;</span><span style="color:#FAB387;font-style:italic;"> str</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#A6E3A1;">    &quot;&quot;&quot;Execute Python code in a sandboxed environment.&quot;&quot;&quot;</span></span>
<span class="line"><span style="color:#CDD6F4;">    sandbox </span><span style="color:#94E2D5;">=</span><span style="color:#89B4FA;"> Sandbox</span><span style="color:#9399B2;">(</span><span style="color:#EBA0AC;font-style:italic;">template</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">&quot;python-data-science&quot;</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#CDD6F4;">    result </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> sandbox</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">run_code</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">code</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#CDD6F4;">    sandbox</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">close</span><span style="color:#9399B2;">()</span></span>
<span class="line"><span style="color:#CBA6F7;">    return</span><span style="color:#CDD6F4;"> result</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">text</span></span></code></pre></div><hr><h2 id="_6-daytona" tabindex="-1">6. Daytona <a class="header-anchor" href="#_6-daytona" aria-label="Permalink to &quot;6. Daytona&quot;">​</a></h2><p><a href="https://github.com/daytonaio/daytona" target="_blank" rel="noreferrer">Daytona</a> is an open-source (AGPL-3.0) sandbox infrastructure designed specifically for coding agents and AI code execution.</p><h3 id="key-differentiators" tabindex="-1">Key Differentiators <a class="header-anchor" href="#key-differentiators" aria-label="Permalink to &quot;Key Differentiators&quot;">​</a></h3><p><strong>Sub-90ms creation time.</strong> Daytona sandboxes spin up faster than Docker containers, using optimized microVM technology and pre-warmed pools.</p><p><strong>Built-in LSP support.</strong> Unlike most sandbox solutions that only offer shell access, Daytona provides Language Server Protocol integration, enabling agents to get code intelligence (autocomplete, diagnostics, go-to-definition) inside the sandbox.</p><p><strong>Unlimited persistence.</strong> Sandboxes can persist indefinitely, unlike E2B&#39;s timeout-based model. This suits long-running agent tasks.</p><p><strong>Multi-language SDKs.</strong> Python, TypeScript, and Go SDKs are available:</p><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">from</span><span style="color:#CDD6F4;"> daytona_sdk </span><span style="color:#CBA6F7;">import</span><span style="color:#CDD6F4;"> Daytona</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CDD6F4;">daytona </span><span style="color:#94E2D5;">=</span><span style="color:#89B4FA;"> Daytona</span><span style="color:#9399B2;">()</span></span>
<span class="line"><span style="color:#CDD6F4;">sandbox </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> daytona</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">create</span><span style="color:#9399B2;">()</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Execute commands</span></span>
<span class="line"><span style="color:#CDD6F4;">response </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> sandbox</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">process</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">exec</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;python3 -c &#39;print(1+1)&#39;&quot;</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#FAB387;font-style:italic;">print</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">response</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">output</span><span style="color:#9399B2;">)</span><span style="color:#6C7086;font-style:italic;">  # &quot;2&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># File operations</span></span>
<span class="line"><span style="color:#CDD6F4;">sandbox</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">fs</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">write_file</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;/home/user/main.py&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;print(&#39;hello&#39;)&quot;</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#CDD6F4;">content </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> sandbox</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">fs</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">read_file</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;/home/user/main.py&quot;</span><span style="color:#9399B2;">)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># LSP integration</span></span>
<span class="line"><span style="color:#CDD6F4;">diagnostics </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> sandbox</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">lsp</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">get_diagnostics</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;/home/user/main.py&quot;</span><span style="color:#9399B2;">)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CDD6F4;">sandbox</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">delete</span><span style="color:#9399B2;">()</span></span></code></pre></div><h3 id="architecture-1" tabindex="-1">Architecture <a class="header-anchor" href="#architecture-1" aria-label="Permalink to &quot;Architecture&quot;">​</a></h3><p>Daytona runs sandboxes as microVMs managed by a control plane. The control plane handles scheduling, networking, and lifecycle management. Each sandbox gets its own network namespace with configurable internet access.</p><hr><h2 id="_7-modal" tabindex="-1">7. Modal <a class="header-anchor" href="#_7-modal" aria-label="Permalink to &quot;7. Modal&quot;">​</a></h2><p><a href="https://modal.com/" target="_blank" rel="noreferrer">Modal</a> is a serverless compute platform that can serve as sandbox infrastructure for coding agents.</p><h3 id="how-it-works-2" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works-2" aria-label="Permalink to &quot;How It Works&quot;">​</a></h3><p>Modal runs functions in isolated containers with automatic scaling. For agent sandboxing, you define a function that executes in a fresh container:</p><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">import</span><span style="color:#CDD6F4;"> modal</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CDD6F4;">app </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> modal</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">App</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;agent-sandbox&quot;</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#CDD6F4;">image </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> modal</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">Image</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">debian_slim</span><span style="color:#9399B2;">().</span><span style="color:#89B4FA;">pip_install</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;numpy&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;pandas&quot;</span><span style="color:#9399B2;">)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#FAB387;font-style:italic;">@app</span><span style="color:#9399B2;">.</span><span style="color:#FAB387;font-style:italic;">function</span><span style="color:#9399B2;">(</span><span style="color:#EBA0AC;font-style:italic;">image</span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;">image</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;font-style:italic;"> timeout</span><span style="color:#94E2D5;">=</span><span style="color:#FAB387;">300</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#CBA6F7;">def</span><span style="color:#89B4FA;font-style:italic;"> execute_in_sandbox</span><span style="color:#9399B2;">(</span><span style="color:#EBA0AC;font-style:italic;">code</span><span style="color:#9399B2;">:</span><span style="color:#FAB387;font-style:italic;"> str</span><span style="color:#9399B2;">)</span><span style="color:#9399B2;"> -&gt;</span><span style="color:#FAB387;font-style:italic;"> str</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#CBA6F7;">    import</span><span style="color:#CDD6F4;"> subprocess</span></span>
<span class="line"><span style="color:#CDD6F4;">    result </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> subprocess</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">run</span><span style="color:#9399B2;">(</span></span>
<span class="line"><span style="color:#9399B2;">        [</span><span style="color:#A6E3A1;">&quot;python3&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;-c&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> code</span><span style="color:#9399B2;">],</span></span>
<span class="line"><span style="color:#EBA0AC;font-style:italic;">        capture_output</span><span style="color:#94E2D5;">=</span><span style="color:#CBA6F7;">True</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;font-style:italic;"> text</span><span style="color:#94E2D5;">=</span><span style="color:#CBA6F7;">True</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;font-style:italic;"> timeout</span><span style="color:#94E2D5;">=</span><span style="color:#FAB387;">60</span></span>
<span class="line"><span style="color:#9399B2;">    )</span></span>
<span class="line"><span style="color:#CBA6F7;">    return</span><span style="color:#CDD6F4;"> result</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">stdout </span><span style="color:#94E2D5;">+</span><span style="color:#CDD6F4;"> result</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">stderr</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># From agent code:</span></span>
<span class="line"><span style="color:#CBA6F7;">with</span><span style="color:#CDD6F4;"> app</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">run</span><span style="color:#9399B2;">():</span></span>
<span class="line"><span style="color:#CDD6F4;">    output </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> execute_in_sandbox</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">remote</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;print(&#39;hello&#39;)&quot;</span><span style="color:#9399B2;">)</span></span></code></pre></div><h3 id="key-features-for-agent-sandboxing" tabindex="-1">Key Features for Agent Sandboxing <a class="header-anchor" href="#key-features-for-agent-sandboxing" aria-label="Permalink to &quot;Key Features for Agent Sandboxing&quot;">​</a></h3><ul><li><strong>GPU support</strong> — agents can run ML code with GPU acceleration</li><li><strong>Function-level isolation</strong> — each invocation gets a fresh container</li><li><strong>Persistent volumes</strong> — shared storage across invocations if needed</li><li><strong>Network control</strong> — configurable egress rules</li><li><strong>Sub-second cold starts</strong> for pre-built images</li><li><strong>Built-in secrets management</strong> — pass credentials without exposing to agent</li></ul><hr><h2 id="_8-firejail" tabindex="-1">8. Firejail <a class="header-anchor" href="#_8-firejail" aria-label="Permalink to &quot;8. Firejail&quot;">​</a></h2><p><a href="https://firejail.wordpress.com/" target="_blank" rel="noreferrer">Firejail</a> is a lightweight Linux sandboxing tool that uses namespaces and seccomp-bpf, similar to bubblewrap but with a different philosophy.</p><h3 id="firejail-vs-bubblewrap" tabindex="-1">Firejail vs bubblewrap <a class="header-anchor" href="#firejail-vs-bubblewrap" aria-label="Permalink to &quot;Firejail vs bubblewrap&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Aspect</th><th>Firejail</th><th>bubblewrap</th></tr></thead><tbody><tr><td>Philosophy</td><td>Feature-rich, desktop-focused</td><td>Minimal, composable</td></tr><tr><td>Profiles</td><td>1000+ app-specific profiles</td><td>No built-in profiles</td></tr><tr><td>Setuid</td><td>Runs as setuid root</td><td>Unprivileged (user ns)</td></tr><tr><td>Network</td><td>Built-in network management</td><td>Namespace only</td></tr><tr><td>X11</td><td>X11 sandboxing support</td><td>No GUI support</td></tr><tr><td>Attack surface</td><td>Larger (more features)</td><td>Smaller (minimal code)</td></tr><tr><td>Best for</td><td>Desktop app isolation</td><td>Programmatic embedding</td></tr></tbody></table><h3 id="usage-for-agents" tabindex="-1">Usage for Agents <a class="header-anchor" href="#usage-for-agents" aria-label="Permalink to &quot;Usage for Agents&quot;">​</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Run agent command in Firejail sandbox</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">firejail</span><span style="color:#A6E3A1;"> --noprofile</span><span style="color:#F5C2E7;"> \\</span></span>
<span class="line"><span style="color:#A6E3A1;">  --net=none</span><span style="color:#F5C2E7;"> \\</span></span>
<span class="line"><span style="color:#A6E3A1;">  --private=/tmp/sandbox</span><span style="color:#F5C2E7;"> \\</span></span>
<span class="line"><span style="color:#A6E3A1;">  --read-only=/usr</span><span style="color:#F5C2E7;"> \\</span></span>
<span class="line"><span style="color:#A6E3A1;">  --seccomp</span><span style="color:#F5C2E7;"> \\</span></span>
<span class="line"><span style="color:#A6E3A1;">  --noroot</span><span style="color:#F5C2E7;"> \\</span></span>
<span class="line"><span style="color:#A6E3A1;">  --caps.drop=all</span><span style="color:#F5C2E7;"> \\</span></span>
<span class="line"><span style="color:#A6E3A1;">  --</span><span style="color:#A6E3A1;"> python3</span><span style="color:#A6E3A1;"> agent_script.py</span></span></code></pre></div><p>Firejail&#39;s security profiles make it easy to sandbox specific tools:</p><div class="language-ini"><button title="Copy Code" class="copy"></button><span class="lang">ini</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># /etc/firejail/python3.profile</span></span>
<span class="line"><span style="color:#CDD6F4;">include /etc/firejail/disable-common.inc</span></span>
<span class="line"><span style="color:#CDD6F4;">net none</span></span>
<span class="line"><span style="color:#CDD6F4;">no3d</span></span>
<span class="line"><span style="color:#CDD6F4;">nosound</span></span>
<span class="line"><span style="color:#CDD6F4;">seccomp</span></span>
<span class="line"><span style="color:#CDD6F4;">caps.drop all</span></span>
<span class="line"><span style="color:#CDD6F4;">noroot</span></span>
<span class="line"><span style="color:#CDD6F4;">private-tmp</span></span></code></pre></div><p>For agent use cases, bubblewrap is generally preferred because it is designed to be embedded programmatically, while Firejail is designed for interactive desktop use. However, Firejail&#39;s pre-built profiles can be useful for quickly sandboxing specific tools without writing custom configuration.</p><hr><h2 id="_9-gemini-cli-s-multi-tier-approach" tabindex="-1">9. Gemini CLI&#39;s Multi-Tier Approach <a class="header-anchor" href="#_9-gemini-cli-s-multi-tier-approach" aria-label="Permalink to &quot;9. Gemini CLI&#39;s Multi-Tier Approach&quot;">​</a></h2><p>Google&#39;s Gemini CLI implements a tiered sandboxing strategy that assigns different isolation levels to different tool types, recognizing that not all operations carry equal risk.</p><h3 id="platform-specific-sandboxing" tabindex="-1">Platform-Specific Sandboxing <a class="header-anchor" href="#platform-specific-sandboxing" aria-label="Permalink to &quot;Platform-Specific Sandboxing&quot;">​</a></h3><p><strong>macOS: Seatbelt profiles.</strong> Gemini CLI uses Apple&#39;s <code>sandbox-exec</code> with custom profiles for shell command execution:</p><div class="language-scheme"><button title="Copy Code" class="copy"></button><span class="lang">scheme</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">version </span><span style="color:#FAB387;">1</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">deny default</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">allow process-fork</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">allow process-exec</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">allow file-read* </span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">subpath </span><span style="color:#A6E3A1;">&quot;/usr&quot;</span><span style="color:#9399B2;">)</span><span style="color:#9399B2;"> (</span><span style="color:#CDD6F4;">subpath </span><span style="color:#A6E3A1;">&quot;/Library&quot;</span><span style="color:#9399B2;">))</span></span>
<span class="line"><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">allow file-read* </span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">subpath </span><span style="color:#A6E3A1;">&quot;/path/to/project&quot;</span><span style="color:#9399B2;">))</span></span>
<span class="line"><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">allow file-write* </span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">subpath </span><span style="color:#A6E3A1;">&quot;/path/to/project&quot;</span><span style="color:#9399B2;">))</span></span>
<span class="line"><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">deny network*</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">allow sysctl-read</span><span style="color:#9399B2;">)</span></span></code></pre></div><p><strong>Linux: Docker containers.</strong> When Docker is available, shell commands execute inside lightweight containers. When Docker is unavailable, Gemini falls back to reduced-privilege execution.</p><h3 id="per-tool-risk-classification" tabindex="-1">Per-Tool Risk Classification <a class="header-anchor" href="#per-tool-risk-classification" aria-label="Permalink to &quot;Per-Tool Risk Classification&quot;">​</a></h3><p>Gemini CLI classifies tools by risk level:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>  High Risk (always sandboxed):</span></span>
<span class="line"><span>  |-- Shell command execution</span></span>
<span class="line"><span>  |-- Code execution</span></span>
<span class="line"><span>  +-- Package installation</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  Medium Risk (configurable):</span></span>
<span class="line"><span>  |-- File write operations</span></span>
<span class="line"><span>  |-- File delete operations</span></span>
<span class="line"><span>  +-- Git operations</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  Low Risk (no sandbox):</span></span>
<span class="line"><span>  |-- File read operations</span></span>
<span class="line"><span>  |-- Directory listing</span></span>
<span class="line"><span>  +-- Search/grep</span></span></code></pre></div><p>This tiered approach reduces overhead — read operations run at native speed while dangerous operations pay the sandbox cost. The configuration is adjustable, allowing users to tighten or loosen restrictions based on their trust level.</p><h3 id="key-design-decision" tabindex="-1">Key Design Decision <a class="header-anchor" href="#key-design-decision" aria-label="Permalink to &quot;Key Design Decision&quot;">​</a></h3><p>Unlike Codex (which sandboxes everything uniformly), Gemini CLI&#39;s approach acknowledges that the cost-benefit of sandboxing varies by operation. Reading a file is inherently safe; there is no security benefit to sandboxing it. This selective approach reduces latency for common operations.</p><hr><h2 id="_10-mini-swe-agent-no-sandbox-natural-isolation" tabindex="-1">10. mini-SWE-agent: No Sandbox (Natural Isolation) <a class="header-anchor" href="#_10-mini-swe-agent-no-sandbox-natural-isolation" aria-label="Permalink to &quot;10. mini-SWE-agent: No Sandbox (Natural Isolation)&quot;">​</a></h2><p><a href="https://github.com/princeton-nlp/SWE-agent" target="_blank" rel="noreferrer">mini-SWE-agent</a> demonstrates that minimal architectures can achieve reasonable isolation through statelessness rather than explicit sandboxing.</p><h3 id="how-it-works-3" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works-3" aria-label="Permalink to &quot;How It Works&quot;">​</a></h3><p>Each action is a fresh <code>subprocess.run()</code> call:</p><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">def</span><span style="color:#89B4FA;font-style:italic;"> execute_action</span><span style="color:#9399B2;">(</span><span style="color:#EBA0AC;font-style:italic;">command</span><span style="color:#9399B2;">:</span><span style="color:#FAB387;font-style:italic;"> str</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;font-style:italic;"> timeout</span><span style="color:#9399B2;">:</span><span style="color:#FAB387;font-style:italic;"> int</span><span style="color:#94E2D5;"> =</span><span style="color:#FAB387;"> 30</span><span style="color:#9399B2;">)</span><span style="color:#9399B2;"> -&gt;</span><span style="color:#FAB387;font-style:italic;"> str</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#CDD6F4;">    result </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> subprocess</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">run</span><span style="color:#9399B2;">(</span></span>
<span class="line"><span style="color:#9399B2;">        [</span><span style="color:#A6E3A1;">&quot;bash&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;-c&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> command</span><span style="color:#9399B2;">],</span></span>
<span class="line"><span style="color:#EBA0AC;font-style:italic;">        capture_output</span><span style="color:#94E2D5;">=</span><span style="color:#CBA6F7;">True</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#EBA0AC;font-style:italic;">        text</span><span style="color:#94E2D5;">=</span><span style="color:#CBA6F7;">True</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#EBA0AC;font-style:italic;">        timeout</span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;">timeout</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#EBA0AC;font-style:italic;">        cwd</span><span style="color:#94E2D5;">=</span><span style="color:#F38BA8;font-style:italic;">self</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">workspace_dir</span></span>
<span class="line"><span style="color:#9399B2;">    )</span></span>
<span class="line"><span style="color:#CBA6F7;">    return</span><span style="color:#CDD6F4;"> result</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">stdout </span><span style="color:#94E2D5;">+</span><span style="color:#CDD6F4;"> result</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">stderr</span></span></code></pre></div><h3 id="natural-isolation-properties" tabindex="-1">Natural Isolation Properties <a class="header-anchor" href="#natural-isolation-properties" aria-label="Permalink to &quot;Natural Isolation Properties&quot;">​</a></h3><ul><li><strong>No persistent shell state</strong> — each command starts fresh (no environment variable leakage between actions, no background processes surviving)</li><li><strong>Working directory scoping</strong> — <code>cwd</code> parameter limits default file access</li><li><strong>Timeout enforcement</strong> — prevents runaway processes</li><li><strong>No network restrictions</strong> — this is the main weakness</li></ul><h3 id="when-this-is-sufficient" tabindex="-1">When This Is Sufficient <a class="header-anchor" href="#when-this-is-sufficient" aria-label="Permalink to &quot;When This Is Sufficient&quot;">​</a></h3><p>For benchmark evaluation (SWE-bench), mini-SWE-agent runs inside a Docker container provided by the benchmark harness. The Docker container IS the sandbox. The agent itself does not need sandboxing because the external environment provides it.</p><p>This pattern — &quot;let the deployment environment handle sandboxing&quot; — is common in simple agents. It works when you control the deployment but is dangerous when running on a developer&#39;s local machine.</p><hr><h2 id="_11-capy-full-vm-per-task" tabindex="-1">11. Capy: Full VM Per Task <a class="header-anchor" href="#_11-capy-full-vm-per-task" aria-label="Permalink to &quot;11. Capy: Full VM Per Task&quot;">​</a></h2><p><a href="https://github.com/cappyai/capy" target="_blank" rel="noreferrer">Capy</a> takes the most heavyweight approach: every task gets a complete Ubuntu virtual machine with <code>sudo</code> access.</p><h3 id="design-philosophy" tabindex="-1">Design Philosophy <a class="header-anchor" href="#design-philosophy" aria-label="Permalink to &quot;Design Philosophy&quot;">​</a></h3><p>Rather than restricting what the agent can do inside the sandbox, Capy gives the agent full root access inside a disposable VM. The agent can install packages, modify system configuration, run services — anything. The VM is destroyed after the task completes, so nothing persists.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>  +---------------------------------------------+</span></span>
<span class="line"><span>  |  Orchestrator                                |</span></span>
<span class="line"><span>  |  +-------------+  +-------------+            |</span></span>
<span class="line"><span>  |  |  Task 1 VM  |  |  Task 2 VM  |  ...      |</span></span>
<span class="line"><span>  |  |  Ubuntu 22  |  |  Ubuntu 22  |            |</span></span>
<span class="line"><span>  |  |  sudo root  |  |  sudo root  |            |</span></span>
<span class="line"><span>  |  |  +-------+  |  |  +-------+  |            |</span></span>
<span class="line"><span>  |  |  | Agent |  |  |  | Agent |  |            |</span></span>
<span class="line"><span>  |  |  +-------+  |  |  +-------+  |            |</span></span>
<span class="line"><span>  |  +-------------+  +-------------+            |</span></span>
<span class="line"><span>  +---------------------------------------------+</span></span></code></pre></div><h3 id="trade-offs-1" tabindex="-1">Trade-offs <a class="header-anchor" href="#trade-offs-1" aria-label="Permalink to &quot;Trade-offs&quot;">​</a></h3><p><strong>Advantages:</strong></p><ul><li><strong>Maximum freedom</strong> — agent can do anything a developer can</li><li><strong>Complete isolation</strong> — VMs share nothing (no kernel, no filesystem)</li><li><strong>Reproducible</strong> — fresh VM means deterministic starting state</li><li><strong>No sandboxing complexity</strong> — no seccomp rules to maintain</li></ul><p><strong>Disadvantages:</strong></p><ul><li><strong>Startup time</strong> — VMs take 10-60 seconds to boot</li><li><strong>Resource cost</strong> — each VM needs dedicated RAM, CPU, disk</li><li><strong>Network control</strong> — internet access restricted to package managers only</li><li><strong>Not practical for interactive use</strong> — too slow for edit-test loops</li></ul><h3 id="when-vms-make-sense" tabindex="-1">When VMs Make Sense <a class="header-anchor" href="#when-vms-make-sense" aria-label="Permalink to &quot;When VMs Make Sense&quot;">​</a></h3><p>Full VMs are appropriate when:</p><ul><li>Tasks require system-level changes (installing system packages, configuring services)</li><li>Security requirements are extremely high (financial, medical, government)</li><li>Tasks are long-running and the startup cost is amortized</li><li>Multi-user environments where cross-task isolation is critical</li></ul><hr><h2 id="_12-comparison-table" tabindex="-1">12. Comparison Table <a class="header-anchor" href="#_12-comparison-table" aria-label="Permalink to &quot;12. Comparison Table&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Solution</th><th>Isolation Level</th><th>Overhead</th><th>Root Required?</th><th>Platform</th><th>Persistent State</th><th>Network Control</th><th>Agent Using It</th></tr></thead><tbody><tr><td><strong>bubblewrap</strong></td><td>Namespace</td><td>~1ms</td><td>No (user ns)</td><td>Linux</td><td>Yes</td><td>Namespace + seccomp</td><td>Codex CLI</td></tr><tr><td><strong>seccomp</strong></td><td>Syscall filter</td><td>~0.1ms</td><td>No</td><td>Linux</td><td>N/A (layer)</td><td>Socket type filtering</td><td>Codex CLI</td></tr><tr><td><strong>Landlock</strong></td><td>Filesystem</td><td>~0.1ms</td><td>No</td><td>Linux 5.13+</td><td>N/A (layer)</td><td>None</td><td>Codex CLI</td></tr><tr><td><strong>Seatbelt</strong></td><td>Process sandbox</td><td>~1ms</td><td>No</td><td>macOS</td><td>Yes</td><td>Profile-based</td><td>Codex, Gemini CLI</td></tr><tr><td><strong>Docker</strong></td><td>Container</td><td>2-10s start</td><td>Yes (daemon)</td><td>Linux/macOS/Win</td><td>Configurable</td><td>Network policies</td><td>OpenHands</td></tr><tr><td><strong>gVisor</strong></td><td>App kernel</td><td>5-15% CPU</td><td>No (OCI)</td><td>Linux</td><td>Configurable</td><td>Container networking</td><td>(Custom setups)</td></tr><tr><td><strong>E2B</strong></td><td>MicroVM (cloud)</td><td>~150ms</td><td>No (SaaS)</td><td>Any (API)</td><td>Configurable</td><td>Configurable</td><td>LangChain agents</td></tr><tr><td><strong>Daytona</strong></td><td>MicroVM</td><td>&lt;90ms</td><td>No (SaaS/self)</td><td>Any (API)</td><td>Unlimited</td><td>Configurable</td><td>(Various)</td></tr><tr><td><strong>Modal</strong></td><td>Container</td><td>&lt;1s</td><td>No (SaaS)</td><td>Any (API)</td><td>Volumes</td><td>Egress rules</td><td>(Custom agents)</td></tr><tr><td><strong>Firejail</strong></td><td>Namespace</td><td>~1ms</td><td>Yes (setuid)</td><td>Linux</td><td>Private fs</td><td>Namespace</td><td>(Custom setups)</td></tr><tr><td><strong>Full VM</strong></td><td>Hardware VM</td><td>10-60s</td><td>Yes</td><td>Any</td><td>Per-VM</td><td>Firewall rules</td><td>Capy</td></tr><tr><td><strong>None</strong></td><td>Process only</td><td>~0ms</td><td>No</td><td>Any</td><td>No</td><td>None</td><td>mini-SWE-agent</td></tr></tbody></table><h3 id="isolation-spectrum" tabindex="-1">Isolation Spectrum <a class="header-anchor" href="#isolation-spectrum" aria-label="Permalink to &quot;Isolation Spectrum&quot;">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>  Weakest                                                          Strongest</span></span>
<span class="line"><span>  &lt;---------------------------------------------------------------------------&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  subprocess    Landlock    bubblewrap    Firejail    Docker    gVisor    VM</span></span>
<span class="line"><span>  (no sandbox)  (fs only)   (namespaces)  (ns+prof)  (container) (app    (full</span></span>
<span class="line"><span>                                                                 kernel)  hw)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  ~0 overhead   ~0.1ms      ~1ms          ~1ms       2-10s     5-15%    10-60s</span></span>
<span class="line"><span>                                                      start     CPU      start</span></span></code></pre></div><hr><h2 id="_13-security-vs-usability-trade-off" tabindex="-1">13. Security vs Usability Trade-off <a class="header-anchor" href="#_13-security-vs-usability-trade-off" aria-label="Permalink to &quot;13. Security vs Usability Trade-off&quot;">​</a></h2><h3 id="the-spectrum" tabindex="-1">The Spectrum <a class="header-anchor" href="#the-spectrum" aria-label="Permalink to &quot;The Spectrum&quot;">​</a></h3><p>Every sandboxing decision exists on a spectrum between security and usability. More isolation means more safety but also more friction — slower startups, harder debugging, incompatible tools, and frustrated developers.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>  Maximum Security                              Maximum Usability</span></span>
<span class="line"><span>  &lt;----------------------------------------------------------------&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  Air-gapped VM    Cloud sandbox    Docker    Namespace    No sandbox</span></span>
<span class="line"><span>  (Capy)           (E2B/Daytona)    (OpenHands) (Codex)    (mini-SWE)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  * No risk         * Low risk      * Medium    * Good      * Full risk</span></span>
<span class="line"><span>  * 60s startup     * 150ms startup * 5s start  * 1ms start * 0ms</span></span>
<span class="line"><span>  * Hard to debug   * API overhead  * Docker    * Linux     * Any env</span></span>
<span class="line"><span>  * Full sudo       * Template mgmt   required    only      * Easy debug</span></span></code></pre></div><h3 id="how-agents-find-the-right-balance" tabindex="-1">How Agents Find the Right Balance <a class="header-anchor" href="#how-agents-find-the-right-balance" aria-label="Permalink to &quot;How Agents Find the Right Balance&quot;">​</a></h3><p><strong>Codex&#39;s insight:</strong> Layer cheap mechanisms (Landlock + seccomp cost nearly nothing) and use expensive mechanisms (namespaces) only when needed. The overhead is dominated by LLM API latency anyway, so sub-second sandbox setup is effectively free.</p><p><strong>OpenHands&#39; insight:</strong> Developers already have Docker installed. Use what is available rather than requiring exotic kernel features. The startup cost is acceptable for task-level granularity (one container per conversation, not per command).</p><p><strong>E2B/Daytona&#39;s insight:</strong> Push the sandbox to the cloud. The agent framework does not need to know about Linux security primitives. An API call creates an isolated environment, and the complexity is someone else&#39;s problem.</p><p><strong>Gemini CLI&#39;s insight:</strong> Not all operations are equally dangerous. Sandbox the risky ones (shell commands, code execution), skip sandboxing for safe ones (file reads, searches). This minimizes overhead while maintaining security where it matters.</p><h3 id="the-trust-hierarchy" tabindex="-1">The Trust Hierarchy <a class="header-anchor" href="#the-trust-hierarchy" aria-label="Permalink to &quot;The Trust Hierarchy&quot;">​</a></h3><p>Agents implement a hierarchy of trust based on the source of the action:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>  Most trusted                              Least trusted</span></span>
<span class="line"><span>  &lt;------------------------------------------------------------&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  User-written     Agent-planned    LLM-generated    External</span></span>
<span class="line"><span>  config/rules     file edits       shell commands    content</span></span>
<span class="line"><span>                                                      (prompt</span></span>
<span class="line"><span>                                                       injection)</span></span></code></pre></div><p>Sandboxing intensity should scale inversely with trust. User configuration runs unsandboxed. LLM-generated shell commands run in full sandbox. This adaptive approach maximizes both security and usability.</p><h3 id="the-future" tabindex="-1">The Future <a class="header-anchor" href="#the-future" aria-label="Permalink to &quot;The Future&quot;">​</a></h3><p>The trend is toward <strong>transparent sandboxing</strong> — mechanisms so lightweight that they are always on, with no user-visible overhead. Landlock and seccomp are approaching this ideal on Linux. As these primitives mature, the trade-off between security and usability will continue to narrow, eventually making &quot;no sandbox&quot; an indefensible choice for any agent that executes code.</p><hr><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ul><li><a href="https://github.com/openai/codex/tree/main/codex-cli/src/os" target="_blank" rel="noreferrer">Codex CLI sandbox implementation</a></li><li><a href="https://github.com/containers/bubblewrap" target="_blank" rel="noreferrer">bubblewrap</a></li><li><a href="https://landlock.io/" target="_blank" rel="noreferrer">Landlock LSM</a></li><li><a href="https://www.kernel.org/doc/html/latest/userspace-api/seccomp_filter.html" target="_blank" rel="noreferrer">seccomp-bpf</a></li><li><a href="https://gvisor.dev/" target="_blank" rel="noreferrer">gVisor</a></li><li><a href="https://e2b.dev/docs" target="_blank" rel="noreferrer">E2B</a></li><li><a href="https://github.com/daytonaio/daytona" target="_blank" rel="noreferrer">Daytona</a></li><li><a href="https://modal.com/docs" target="_blank" rel="noreferrer">Modal</a></li><li><a href="https://firejail.wordpress.com/" target="_blank" rel="noreferrer">Firejail</a></li><li><a href="https://docs.all-hands.dev/modules/usage/architecture" target="_blank" rel="noreferrer">OpenHands architecture</a></li><li><a href="https://reverse.put.as/wp-content/uploads/2011/09/Apple-Sandbox-Guide-v1.0.pdf" target="_blank" rel="noreferrer">Apple Sandbox (Seatbelt)</a></li></ul>`,188)])])}const u=a(t,[["render",l]]);export{h as __pageData,u as default};
